import { Link as ExternalLink } from '@yozora/react-link'
import type { LinkProps } from '@yozora/react-link'
import cn from 'clsx'
import { Link as GatsbyLink } from 'gatsby'
import React from 'react'

/**
 * Render yozora `link`.
 * @see https://www.npmjs.com/package/@yozora/tokenizer-link
 */
export function InternalLink(props: LinkProps): React.ReactElement {
  const {
    children, // children is not allowed.
    className,
    url,
    title,
    ...htmlProps
  } = props

  return (
    // eslint-disable-next-line react/jsx-no-target-blank
    <GatsbyLink
      {...htmlProps}
      className={cn('yozora-link', className)}
      to={url}
      title={title}
      replace={true}
    >
      {children}
    </GatsbyLink>
  )
}

InternalLink.propTypes = ExternalLink.propTypes

export default function Link(props: LinkProps): React.ReactElement | null {
  // Hash tag
  if (/^#/.test(props.url)) {
    return (
      <a title={props.title} href={props.url}>
        {props.children}
      </a>
    )
  }

  // External url
  if (/^(\w+:[/]{2})/.test(props.url)) {
    return <ExternalLink {...props} />
  }

  // Internal url
  return <InternalLink {...props} />
}
